// ---------- storage helpers ----------
async function loadCollection(prefix) {
  try {
    const res = await storage.list(prefix, true);
    if (!res || !res.keys) return [];
    const items = await Promise.all(
      res.keys.map(async (k) => {
        try {
          const r = await storage.get(k, true);
          return r ? { key: k, ...JSON.parse(r.value) } : null;
        } catch {
          return null;
        }
      })
    );
    return items.filter(Boolean);
  } catch {
    return [];
  }
}

function useCircuitField(count = 26) {
  const [nodes] = useState(() =>
    Array.from({ length: count }, (_, i) => ({
      id: i,
      x: Math.random() * 100,
      y: Math.random() * 100,
      d: 3 + Math.random() * 4,
      delay: Math.random() * 4,
    }))
  );
  return nodes;
}

function CircuitBackground() {
  const nodes = useCircuitField();
  return (
    <div style={{ position: "absolute", inset: 0, overflow: "hidden", pointerEvents: "none" }}>
      <div
        style={{
          position: "absolute", inset: 0, opacity: 0.35,
          backgroundImage:
            `linear-gradient(${C.line} 1px, transparent 1px), linear-gradient(90deg, ${C.line} 1px, transparent 1px)`,
          backgroundSize: "38px 38px",
        }}
      />
      {nodes.map((n) => (
        <div
          key={n.id}
          style={{
            position: "absolute", left: n.x + "%", top: n.y + "%",
            width: 4, height: 4, borderRadius: "50%",
            background: C.blueLight, opacity: 0.7,
            boxShadow: `0 0 8px ${C.blueLight}`,
            animation: `pulseNode ${n.d}s ease-in-out ${n.delay}s infinite`,
          }}
        />
      ))}
      <style>{`
        @keyframes pulseNode { 0%,100%{opacity:.15; transform:scale(1);} 50%{opacity:.9; transform:scale(1.8);} }
      `}</style>
    </div>
  );
}

