function AdminLoginModal({ onClose, onSuccess }) {
  const [user, setUser] = useState(""); const [pwd, setPwd] = useState(""); const [err, setErr] = useState(false);
  const check = () => { if (checkAdminCreds(user, pwd)) onSuccess(); else setErr(true); };
  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)", zIndex: 300, display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: "#fff", borderRadius: 10, padding: "30px 34px", width: "100%", maxWidth: 320, boxShadow: "0 10px 30px rgba(0,0,0,0.2)" }}>
        <h3 style={{ color: C.navy, fontFamily: "Arial, Helvetica, sans-serif", fontSize: 18, marginBottom: 18, marginTop: 0 }}>Acceso de administrador</h3>
        <label style={{ display: "block", fontSize: 12, color: "#555", marginBottom: 4 }}>Usuario</label>
        <input placeholder="Usuario" value={user} onChange={(e) => { setUser(e.target.value); setErr(false); }} style={{ width: "100%", background: "#fff", border: `1px solid ${err ? "#c0392b" : "#ccc"}`, borderRadius: 6, padding: "9px 10px", color: "#222", outline: "none", fontSize: 14, marginBottom: 9 }} />
        <label style={{ display: "block", fontSize: 12, color: "#555", marginBottom: 4 }}>Contraseña</label>
        <input type="password" placeholder="Contraseña" value={pwd} onChange={(e) => { setPwd(e.target.value); setErr(false); }} onKeyDown={(e) => e.key === "Enter" && check()} style={{ width: "100%", background: "#fff", border: `1px solid ${err ? "#c0392b" : "#ccc"}`, borderRadius: 6, padding: "9px 10px", color: "#222", outline: "none", fontSize: 14, marginBottom: 12 }} />
        {err && <div style={{ color: "#c0392b", fontSize: 12, marginBottom: 10 }}>Usuario o contraseña incorrectos.</div>}
        <div style={{ display: "flex", gap: 10, marginTop: 8 }}>
          <button onClick={onClose} style={{ flex: 1, background: "#eee", color: "#333", border: "none", borderRadius: 6, padding: "10px 0", fontWeight: 700, cursor: "pointer", fontSize: 13 }}>Cancelar</button>
          <button onClick={check} style={{ flex: 1, background: C.navy, color: "#fff", border: "none", borderRadius: 6, padding: "10px 0", fontWeight: 700, cursor: "pointer", fontSize: 13 }}>Entrar</button>
        </div>
      </div>
    </div>
  );
}

