// ================= CAJAS DE ESTADÍSTICAS (Inicio) =================
function CajasEstadisticas({ isAdmin }) {
  const [impacto, setImpacto] = useState(null);
  const [satisfaccion, setSatisfaccion] = useState(null);
  const [clientes, setClientes] = useState(0);
  const [experiencias, setExperiencias] = useState(0);
  const [editando, setEditando] = useState(false);
  const [guardando, setGuardando] = useState(false);

  const cargar = async () => {
    try {
      const r = await storage.get("stats:impacto", true);
      setImpacto(JSON.parse(r.value).n || 0);
    } catch { setImpacto(0); }

    try {
      const opiniones = await loadCollection("comentarios:");
      const foroRes = await storage.list("foropost:", true);
      const foroPosts = foroRes && foroRes.keys
        ? (await Promise.all(foroRes.keys.map(async (k) => { try { const r = await storage.get(k, true); return JSON.parse(r.value); } catch { return null; } }))).filter(Boolean)
        : [];
      const todas = [...opiniones, ...foroPosts];
      if (todas.length === 0) { setSatisfaccion(null); }
      else {
        const suma = todas.reduce((s, it) => s + (CATEGORIAS.find((c) => c.key === it.categoria)?.score || 2), 0);
        setSatisfaccion(Math.round((suma / (todas.length * 3)) * 100));
      }
    } catch { setSatisfaccion(null); }

    try {
      const r = await storage.get("stats:clientes", true);
      setClientes(JSON.parse(r.value).n || 0);
    } catch { setClientes(0); }

    try {
      const r = await storage.get("stats:experiencias", true);
      setExperiencias(JSON.parse(r.value).n || 0);
    } catch { setExperiencias(0); }
  };

  useEffect(() => { cargar(); }, []);

  const guardarManual = async () => {
    setGuardando(true);
    await storage.set("stats:clientes", JSON.stringify({ n: Number(clientes) || 0 }), true);
    await storage.set("stats:experiencias", JSON.stringify({ n: Number(experiencias) || 0 }), true);
    setGuardando(false);
    setEditando(false);
  };

  const cajas = [
    { label: "Impacto", valor: impacto === null ? "…" : impacto.toLocaleString(), icon: Users },
    { label: "Satisfacción de cliente", valor: satisfaccion === null ? "—" : `${satisfaccion}%`, icon: Star },
    { label: "Clientes", valor: clientes.toLocaleString(), icon: ShieldCheck },
    { label: "Experiencias", valor: experiencias.toLocaleString(), icon: Award },
  ];

  return (
    <section style={{ background: C.navyDeep, padding: "46px 8vw 56px" }}>
      <div style={{ maxWidth: 1100, margin: "0 auto" }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(200px,1fr))", gap: 20 }}>
          {cajas.map((c) => (
            <div key={c.label} style={{ background: C.navy, border: `1px solid ${C.lineOnDark}`, borderRadius: 10, padding: "26px 18px", textAlign: "center" }}>
              <c.icon size={24} color={C.gold} style={{ marginBottom: 10 }} />
              <div style={{ color: "#fff", fontFamily: "Arial, Helvetica, sans-serif", fontWeight: 800, fontSize: 28 }}>{c.valor}</div>
              <div style={{ color: C.onDarkDim, fontSize: 13, marginTop: 6 }}>{c.label}</div>
            </div>
          ))}
        </div>

        {isAdmin && (
          <div style={{ marginTop: 18, textAlign: "center" }}>
            {editando ? (
              <div style={{ display: "inline-flex", gap: 10, alignItems: "center", flexWrap: "wrap", background: C.navy, border: `1px solid ${C.lineOnDark}`, borderRadius: 12, padding: 14 }}>
                <label style={{ color: C.onDarkDim, fontSize: 12.5 }}>Clientes:
                  <input type="number" value={clientes} onChange={(e) => setClientes(e.target.value)} style={{ width: 80, marginLeft: 6, background: "#fff", border: `1px solid ${C.lineOnDark}`, borderRadius: 6, padding: "5px 8px", color: C.text }} />
                </label>
                <label style={{ color: C.onDarkDim, fontSize: 12.5 }}>Experiencias:
                  <input type="number" value={experiencias} onChange={(e) => setExperiencias(e.target.value)} style={{ width: 80, marginLeft: 6, background: "#fff", border: `1px solid ${C.lineOnDark}`, borderRadius: 6, padding: "5px 8px", color: C.text }} />
                </label>
                <button onClick={guardarManual} disabled={guardando} style={{ background: C.gold, color: C.navy, border: "none", borderRadius: 8, padding: "7px 14px", fontWeight: 700, cursor: "pointer", fontSize: 12.5 }}>{guardando ? "Guardando…" : "Guardar"}</button>
                <button onClick={() => setEditando(false)} style={{ background: "none", border: `1px solid ${C.lineOnDark}`, color: C.onDarkDim, borderRadius: 8, padding: "7px 14px", cursor: "pointer", fontSize: 12.5 }}>Cerrar</button>
              </div>
            ) : (
              <button onClick={() => setEditando(true)} style={{ background: "none", border: "none", color: C.onDarkDim, cursor: "pointer", fontSize: 11.5 }}>Editar Clientes / Experiencias</button>
            )}
          </div>
        )}
      </div>
    </section>
  );
}

// ================= OPINIONES DE CLIENTES (testimonios, idéntico al modelo) =================
// Único agregado respecto al modelo: tarjetas de comentarios de clientes con
// nombre y empresa. Se agregan, editan y eliminan exclusivamente con el candado activo.
function TestimoniosClientes({ isAdmin }) {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);

  const refresh = useCallback(async () => {
    setLoading(true);
    const data = await loadCollection("testimonios:");
    data.sort((a, b) => (a.fecha || "").localeCompare(b.fecha || ""));
    setItems(data);
    setLoading(false);
  }, []);

  useEffect(() => { refresh(); }, [refresh]);

  const agregar = async () => {
    const id = "testimonios:" + Date.now();
    await storage.set(id, JSON.stringify({
      nombre: "Nombre del cliente", empresa: "Empresa", comentario: "Escribe aquí el comentario del cliente.",
      fecha: new Date().toISOString(),
    }), true);
    await refresh();
  };

  const eliminar = async (item) => {
    await storage.delete(item.key, true);
    setItems((prev) => prev.filter((it) => it.key !== item.key));
  };

  const guardarCampo = async (item, campo, valor) => {
    const actualizado = { ...item, [campo]: valor };
    setItems((prev) => prev.map((it) => (it.key === item.key ? actualizado : it)));
    const { key, ...resto } = actualizado;
    await storage.set(item.key, JSON.stringify(resto), true);
  };

  if (loading && items.length === 0) {
    return (
      <section style={{ background: C.bg, padding: "60px 8vw" }}>
        <SectionHead eyebrow="Confían en nosotros" title="Lo que dicen nuestros clientes" center />
        <div style={{ textAlign: "center", color: C.textDim, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
          <Loader2 size={16} className="animate-spin" /> Cargando comentarios…
        </div>
      </section>
    );
  }

  if (!isAdmin && items.length === 0) return null;

  return (
    <section style={{ background: C.bg, padding: "60px 8vw" }}>
      <SectionHead eyebrow="Confían en nosotros" title="Lo que dicen nuestros clientes" center />

      {items.length === 0 ? (
        <div style={{ textAlign: "center", color: C.textDim, fontSize: 14 }}>
          Aún no hay comentarios de clientes.
        </div>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(240px,1fr))", gap: 22, maxWidth: 1100, margin: "0 auto" }}>
          {items.map((it) => (
            <div key={it.key} style={{ background: "#fff", borderRadius: 10, padding: 22, boxShadow: "0 2px 10px rgba(0,0,0,0.06)", position: "relative" }}>
              {isAdmin && (
                <button
                  onClick={() => eliminar(it)}
                  title="Eliminar"
                  style={{ position: "absolute", top: 10, right: 10, background: "#E24B4A", color: "#fff", border: "none", borderRadius: "50%", width: 22, height: 22, cursor: "pointer", fontSize: 13, display: "flex", alignItems: "center", justifyContent: "center" }}
                >
                  <X size={12} />
                </button>
              )}
              <div style={{ color: "#ccc", fontSize: 40, lineHeight: 0.5, fontFamily: "Georgia, serif" }}>&#8220;</div>
              <p
                contentEditable={isAdmin}
                suppressContentEditableWarning
                onBlur={(e) => isAdmin && guardarCampo(it, "comentario", e.currentTarget.textContent)}
                style={{ color: "#444", fontSize: 14, margin: "12px 0 16px", lineHeight: 1.6, outline: isAdmin ? `1px dashed ${C.gold}` : "none", borderRadius: 4, padding: isAdmin ? 4 : 0 }}
              >
                {it.comentario}
              </p>
              <div
                contentEditable={isAdmin}
                suppressContentEditableWarning
                onBlur={(e) => isAdmin && guardarCampo(it, "nombre", e.currentTarget.textContent)}
                style={{ fontWeight: 700, color: C.navy, fontSize: 14, outline: isAdmin ? `1px dashed ${C.gold}` : "none", borderRadius: 4 }}
              >
                {it.nombre}
              </div>
              <div
                contentEditable={isAdmin}
                suppressContentEditableWarning
                onBlur={(e) => isAdmin && guardarCampo(it, "empresa", e.currentTarget.textContent)}
                style={{ fontSize: 12, color: "#888", outline: isAdmin ? `1px dashed ${C.gold}` : "none", borderRadius: 4 }}
              >
                {it.empresa}
              </div>
            </div>
          ))}
        </div>
      )}

      {isAdmin && (
        <button onClick={agregar} style={{
          display: "block", margin: "26px auto 0", background: C.navy, color: "#fff", border: "none",
          padding: "10px 22px", borderRadius: 6, fontWeight: 700, cursor: "pointer", fontSize: 13,
        }}>
          + Agregar cliente
        </button>
      )}
    </section>
  );
}

// ================= INSCRIPCION =================
function Inscripcion() {
  const empty = { nombre: "", apellido: "", contacto: "", direccion: "", cedula: "", correo: "", horario: "" };
  const [form, setForm] = useState(empty);
  const [saving, setSaving] = useState(false);
  const [done, setDone] = useState(false);
  const [error, setError] = useState("");

  const set = (k) => (e) => setForm((f) => ({ ...f, [k]: e.target.value }));

  const submit = async (e) => {
    e.preventDefault();
    setError("");
    for (const k of Object.keys(empty)) {
      if (!form[k].trim()) {
        setError("Por favor completa todos los campos, incluyendo el horario.");
        return;
      }
    }
    setSaving(true);
    try {
      const id = "inscripciones:" + Date.now();
      await storage.set(id, JSON.stringify({ ...form, fecha: new Date().toISOString() }), true);
      sendEmailNotification({
        subject: "Nueva inscripción — SICODE",
        fromName: "Formulario de inscripción",
        data: form,
      });
      setDone(true);
      const msg = encodeURIComponent(
        "He llenado el formulario de inscripción, ¿cuál es el siguiente paso? Mi número es 8495399825, República Dominicana."
      );
      window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${msg}`, "_blank");
    } catch {
      setError("No se pudo guardar tu inscripción. Intenta de nuevo en unos segundos.");
    } finally {
      setSaving(false);
    }
  };

  const inputStyle = {
    width: "100%", background: C.panel, border: `1px solid ${C.line}`, borderRadius: 10,
    padding: "13px 14px", color: C.text, fontSize: 15, fontFamily: "Arial, Helvetica, sans-serif", outline: "none",
  };
  const label = { fontSize: 13, color: C.textDim, marginBottom: 7, display: "block", fontFamily: "Arial, Helvetica, sans-serif" };

  if (done) {
    return (
      <div style={{ minHeight: "70vh", display: "flex", alignItems: "center", justifyContent: "center", padding: "8vh 8vw", background: C.bg }}>
        <div style={{ textAlign: "center", maxWidth: 480 }}>
          <CheckCircle2 size={54} color={C.blueLight} style={{ marginBottom: 20 }} />
          <h2 style={{ fontFamily: "Arial, Helvetica, sans-serif", color: C.text, fontSize: 28 }}>¡Registrado de manera satisfactoria!</h2>
          <p style={{ color: C.textDim, marginTop: 12, lineHeight: 1.6 }}>
            Te abrimos WhatsApp para confirmar tu cupo. Si no se abrió automáticamente, escríbenos al 849 539 9825.
          </p>
          <button onClick={() => { setForm(empty); setDone(false); }} style={{
            marginTop: 26, background: "transparent", border: `1px solid ${C.line}`, color: C.text,
            padding: "12px 22px", borderRadius: 10, cursor: "pointer",
          }}>
            Registrar otra inscripción
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ background: C.bg, padding: "8vh 8vw", minHeight: "80vh" }}>
      <SectionHead eyebrow="Cupos limitados" title="Formulario de inscripción" />
      <form onSubmit={submit} className="insc-grid" style={{ maxWidth: 640, display: "grid", gridTemplateColumns: "1fr 1fr", gap: 18 }}>
        <div>
          <label style={label}>NOMBRE</label>
          <input style={inputStyle} value={form.nombre} onChange={set("nombre")} placeholder="Juan" />
        </div>
        <div>
          <label style={label}>APELLIDO</label>
          <input style={inputStyle} value={form.apellido} onChange={set("apellido")} placeholder="Pérez" />
        </div>
        <div style={{ gridColumn: "1 / -1" }}>
          <label style={label}><Phone size={12} style={{ display: "inline", marginRight: 6 }} />CONTACTO (TELÉFONO)</label>
          <input style={inputStyle} value={form.contacto} onChange={set("contacto")} placeholder="849 000 0000" />
        </div>
        <div style={{ gridColumn: "1 / -1" }}>
          <label style={label}><MapPin size={12} style={{ display: "inline", marginRight: 6 }} />DIRECCIÓN</label>
          <input style={inputStyle} value={form.direccion} onChange={set("direccion")} placeholder="Calle, número, sector, ciudad" />
        </div>
        <div>
          <label style={label}><CreditCard size={12} style={{ display: "inline", marginRight: 6 }} />CÉDULA (RD)</label>
          <input style={inputStyle} value={form.cedula} onChange={set("cedula")} placeholder="000-0000000-0" />
        </div>
        <div>
          <label style={label}><Mail size={12} style={{ display: "inline", marginRight: 6 }} />CORREO ELECTRÓNICO</label>
          <input style={inputStyle} type="email" value={form.correo} onChange={set("correo")} placeholder="tucorreo@ejemplo.com" />
        </div>
        <div style={{ gridColumn: "1 / -1" }}>
          <label style={label}><Clock size={12} style={{ display: "inline", marginRight: 6 }} />HORARIO</label>
          <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
            {["Martes y jueves · 8:00–10:00 p.m.", "Viernes · 8:00–10:00 p.m."].map((h) => (
              <button
                type="button" key={h}
                onClick={() => setForm((f) => ({ ...f, horario: h }))}
                style={{
                  flex: "1 1 240px", textAlign: "left", padding: "14px 16px", borderRadius: 10,
                  border: `1px solid ${form.horario === h ? C.blueLight : C.line}`,
                  background: form.horario === h ? "rgba(16,48,107,0.12)" : C.panel,
                  color: form.horario === h ? C.blueLight : C.text, cursor: "pointer", fontSize: 14,
                }}
              >
                {h}
              </button>
            ))}
          </div>
        </div>
        {error && <div style={{ gridColumn: "1 / -1", color: "#FF8080", fontSize: 14 }}>{error}</div>}
        <div style={{ gridColumn: "1 / -1" }}>
          <button type="submit" disabled={saving} style={{
            background: C.gold, color: C.navy, border: "none", padding: "15px 26px",
            borderRadius: 10, fontWeight: 700, fontSize: 15, cursor: saving ? "default" : "pointer",
            display: "flex", alignItems: "center", gap: 10, opacity: saving ? 0.7 : 1,
          }}>
            {saving ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
            {saving ? "Enviando..." : "Enviar inscripción"}
          </button>
        </div>
      </form>
    </div>
  );
}

// ================= APOYO =================
function Apoyo({ isAdmin }) {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState(false);
  const [query, setQuery] = useState("");

  const refresh = useCallback(async () => {
    setLoading(true);
    const data = await loadCollection("plantillas:");
    data.sort((a, b) => (b.fecha || "").localeCompare(a.fecha || ""));
    setItems(data);
    setLoading(false);
  }, []);

  useEffect(() => { refresh(); }, [refresh]);

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 4.5 * 1024 * 1024) {
      alert("El archivo es muy grande. El límite es de aproximadamente 4.5MB.");
      return;
    }
    setUploading(true);
    try {
      const uploaded = await uploadToCloudinary(file);
      const safeKey = "plantillas:" + Date.now();
      await storage.set(safeKey, JSON.stringify({
        nombre: file.name, tipo: file.type || "application/octet-stream",
        url: uploaded.url, fecha: new Date().toISOString(),
      }), true);
      await refresh();
    } catch {
      alert("No se pudo subir la plantilla. Intenta de nuevo.");
    } finally {
      setUploading(false);
      e.target.value = "";
    }
  };

  const download = (item) => {
    window.open(item.url, "_blank");
  };

  const removeItem = async (item) => {
    if (!confirm(`¿Eliminar "${item.nombre}"?`)) return;
    await storage.delete(item.key, true);
    await refresh();
  };

  return (
    <div style={{ background: C.bg, padding: "8vh 8vw", minHeight: "80vh" }}>
      <SectionHead eyebrow="Apoyo" title="Plantillas descargables" />
      <p style={{ color: C.textDim, maxWidth: 600, marginTop: -20, marginBottom: 40 }}>
        Descarga las plantillas compartidas por SICODE para tus clases y proyectos.
      </p>

      {isAdmin && (
        <div style={{ marginBottom: 40, background: C.panel, border: `1px solid ${C.line}`, borderRadius: 14, padding: 24 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8, color: C.blueLight, marginBottom: 14 }}>
            <ShieldCheck size={18} /> <span style={{ fontFamily: "Arial, Helvetica, sans-serif", fontSize: 13 }}>MODO PROPIETARIO</span>
          </div>
          <label style={{
            display: "inline-flex", alignItems: "center", gap: 10, background: C.gold, color: C.navy,
            padding: "12px 20px", borderRadius: 10, fontWeight: 700, cursor: "pointer", fontSize: 14,
          }}>
            <Upload size={17} /> {uploading ? "Subiendo..." : "Subir nueva plantilla"}
            <input type="file" onChange={handleUpload} style={{ display: "none" }} disabled={uploading} />
          </label>
        </div>
      )}

      {loading ? (
        <div style={{ color: C.textDim, display: "flex", alignItems: "center", gap: 8 }}><Loader2 size={16} className="animate-spin" /> Cargando plantillas…</div>
      ) : (
        <>
          <div style={{ position: "relative", maxWidth: 380, marginBottom: 24 }}>
            <Search size={16} color={C.textDim} style={{ position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)" }} />
            <input
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Buscar plantilla por nombre..."
              style={{
                width: "100%", background: C.panel, border: `1px solid ${C.line}`, borderRadius: 10,
                padding: "11px 14px 11px 40px", color: C.text, fontSize: 14, outline: "none",
              }}
            />
          </div>
          {(() => {
            const filtered = items.filter((it) => it.nombre.toLowerCase().includes(query.toLowerCase()));
            if (items.length === 0) return <div style={{ color: C.textDim }}>Aún no hay plantillas disponibles.</div>;
            if (filtered.length === 0) return <div style={{ color: C.textDim }}>No encontramos plantillas que coincidan con "{query}".</div>;
            return (
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(260px,1fr))", gap: 16 }}>
                {filtered.map((it) => (
                  <div key={it.key} style={{ background: C.panel, border: `1px solid ${C.line}`, borderRadius: 14, padding: 20, display: "flex", flexDirection: "column", gap: 14 }}>
                    <div style={{ color: C.text, fontWeight: 600, fontSize: 15, wordBreak: "break-word" }}>{it.nombre}</div>
                    <div style={{ display: "flex", gap: 10 }}>
                      <button onClick={() => download(it)} style={{ flex: 1, background: "rgba(16,48,107,0.12)", color: C.blueLight, border: "none", borderRadius: 8, padding: "9px 0", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 6, fontSize: 13 }}>
                        <Download size={15} /> Descargar
                      </button>
                      {isAdmin && (
                        <button onClick={() => removeItem(it)} style={{ background: "rgba(255,90,90,0.12)", color: "#FF8080", border: "none", borderRadius: 8, padding: "9px 12px", cursor: "pointer" }}>
                          <Trash2 size={15} />
                        </button>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            );
          })()}
        </>
      )}
    </div>
  );
}

// ================= OPINIONES =================
const CATEGORIAS = [
  { key: "no", label: "No recomendado", score: 1, color: "#FF6B6B" },
  { key: "si", label: "Se recomienda", score: 2, color: C.gold },
  { key: "muy", label: "Muy recomendado", score: 3, color: C.blueLight },
];

// Cuenta una visita al sitio para la cajita "Impacto" (una vez por visita/sesión).
async function registrarVisitaImpacto() {
  try {
    if (typeof window === "undefined") return;
    if (sessionStorage.getItem("sicode_visita_contada")) return;
    sessionStorage.setItem("sicode_visita_contada", "1");
    let n = 0;
    try {
      const actual = await storage.get("stats:impacto", true);
      n = actual ? (JSON.parse(actual.value).n || 0) : 0;
    } catch {}
    await storage.set("stats:impacto", JSON.stringify({ n: n + 1 }), true);
  } catch {}
}

function Opiniones({ isAdmin }) {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({ nombre: "", correo: "", comentario: "", categoria: "muy" });
  const [saving, setSaving] = useState(false);
  const [sent, setSent] = useState(false);

  const refresh = useCallback(async () => {
    setLoading(true);
    const data = await loadCollection("comentarios:");
    data.sort((a, b) => (b.fecha || "").localeCompare(a.fecha || ""));
    setItems(data);
    setLoading(false);
  }, []);

  useEffect(() => { refresh(); }, [refresh]);

  const avg = items.length
    ? items.reduce((s, i) => s + (CATEGORIAS.find((c) => c.key === i.categoria)?.score || 2), 0) / items.length
    : 0;

  const submit = async (e) => {
    e.preventDefault();
    if (!form.nombre.trim() || !form.comentario.trim()) return;
    setSaving(true);
    try {
      const id = "comentarios:" + Date.now();
      await storage.set(id, JSON.stringify({ ...form, fecha: new Date().toISOString() }), true);
      sendEmailNotification({
        subject: "Nueva opinión en el sitio — SICODE",
        fromName: "Opiniones del sitio",
        data: form,
      });
      setForm({ nombre: "", correo: "", comentario: "", categoria: "muy" });
      await refresh();
      setSent(true);
      setTimeout(() => setSent(false), 6000);
    } catch {
      alert("No se pudo publicar tu comentario.");
    } finally {
      setSaving(false);
    }
  };

  const inputStyle = {
    width: "100%", background: C.panel, border: `1px solid ${C.line}`, borderRadius: 10,
    padding: "12px 14px", color: C.text, fontSize: 14.5, outline: "none", fontFamily: "Arial, Helvetica, sans-serif",
  };

  return (
    <div style={{ background: C.bg, padding: "8vh 8vw", minHeight: "80vh" }}>
      <SectionHead eyebrow="Tu opinión cuenta" title="Opiniones del sitio" />

      <div style={{ display: "flex", gap: 40, alignItems: "flex-start", flexWrap: "wrap" }}>
        <div style={{ flex: "2 1 480px", minWidth: 300 }}>

      <div style={{ display: "flex", gap: 26, alignItems: "center", marginTop: -20, marginBottom: 44, flexWrap: "wrap" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <MessageCircle size={18} color={C.blueLight} />
          <span style={{ color: C.text, fontFamily: "Arial, Helvetica, sans-serif" }}>{items.length} comentario{items.length !== 1 ? "s" : ""}</span>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <Star size={18} color={C.gold} />
          <span style={{ color: C.text, fontFamily: "Arial, Helvetica, sans-serif" }}>
            {items.length ? `${avg.toFixed(1)} / 3 · ${avg >= 2.5 ? "Muy recomendado" : avg >= 1.5 ? "Se recomienda" : "No recomendado"}` : "Sin puntuación aún"}
          </span>
        </div>
      </div>

      <form onSubmit={submit} style={{ maxWidth: 560, display: "flex", flexDirection: "column", gap: 14, marginBottom: 56, background: C.panel, border: `1px solid ${C.line}`, borderRadius: 16, padding: 26 }}>
        <input style={inputStyle} placeholder="Tu nombre" value={form.nombre} onChange={(e) => setForm((f) => ({ ...f, nombre: e.target.value }))} />
        <input style={inputStyle} placeholder="Correo (opcional)" value={form.correo} onChange={(e) => setForm((f) => ({ ...f, correo: e.target.value }))} />
        <textarea style={{ ...inputStyle, minHeight: 90, resize: "vertical" }} placeholder="Cuéntanos tu experiencia..." value={form.comentario} onChange={(e) => setForm((f) => ({ ...f, comentario: e.target.value }))} />
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
          {CATEGORIAS.map((c) => (
            <button type="button" key={c.key} onClick={() => setForm((f) => ({ ...f, categoria: c.key }))}
              style={{
                padding: "9px 16px", borderRadius: 999, fontSize: 13, cursor: "pointer",
                border: `1px solid ${form.categoria === c.key ? c.color : C.line}`,
                background: form.categoria === c.key ? c.color + "22" : "transparent",
                color: form.categoria === c.key ? c.color : C.textDim,
              }}>
              {c.label}
            </button>
          ))}
        </div>
        <button type="submit" disabled={saving} style={{
          alignSelf: "flex-start", background: C.gold, color: C.navy, border: "none",
          padding: "12px 22px", borderRadius: 10, fontWeight: 700, cursor: "pointer",
          display: "flex", alignItems: "center", gap: 8, opacity: saving ? 0.7 : 1,
        }}>
          {saving ? <Loader2 size={16} className="animate-spin" /> : <Send size={16} />}
          Publicar comentario
        </button>
        {sent && (
          <div style={{
            display: "flex", alignItems: "center", gap: 8, color: C.blueLight,
            background: C.blueLight + "18", border: `1px solid ${C.blueLight}55`,
            borderRadius: 10, padding: "10px 14px", fontSize: 14,
          }}>
            <CheckCircle2 size={18} />
            Tu comentario se agregó correctamente. ¡Gracias por hacernos crecer!
          </div>
        )}
      </form>

      {loading ? (
        <div style={{ color: C.textDim, display: "flex", alignItems: "center", gap: 8 }}><Loader2 size={16} className="animate-spin" /> Cargando comentarios…</div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 14, maxWidth: 720 }}>
          {items.map((it) => {
            const cat = CATEGORIAS.find((c) => c.key === it.categoria) || CATEGORIAS[1];
            return (
              <div key={it.key} style={{ background: C.panel, border: `1px solid ${C.line}`, borderRadius: 14, padding: 20 }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10, flexWrap: "wrap", gap: 8 }}>
                  <span style={{ color: C.text, fontWeight: 600 }}>{it.nombre}</span>
                  <span style={{ fontSize: 12, padding: "4px 12px", borderRadius: 999, color: cat.color, border: `1px solid ${cat.color}55`, fontFamily: "Arial, Helvetica, sans-serif" }}>{cat.label}</span>
                </div>
                <p style={{ color: C.textDim, margin: 0, lineHeight: 1.55, fontSize: 14.5 }}>{it.comentario}</p>
              </div>
            );
          })}
        </div>
      )}

        </div>
        <div style={{ flex: "1 1 280px", minWidth: 260 }}>
          <ForoPanel isAdmin={isAdmin} />
        </div>
      </div>
    </div>
  );
}

// ================= CLIENTES =================
function Clientes({ isAdmin }) {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [current, setCurrent] = useState(0);
  const [showAdd, setShowAdd] = useState(false);
  const [nombre, setNombre] = useState("");
  const [foto, setFoto] = useState(null);
  const [saving, setSaving] = useState(false);
  const [tamanoLogo, setTamanoLogo] = useState(220);

  const TAMANOS_LOGO = [["Pequeño", 110], ["Mediano", 150], ["Grande", 220], ["Muy grande", 280]];

  const refresh = useCallback(async () => {
    setLoading(true);
    const data = await loadCollection("clientes:");
    data.sort((a, b) => (a.fecha || "").localeCompare(b.fecha || ""));
    setItems(data);
    setLoading(false);
  }, []);

  useEffect(() => { refresh(); }, [refresh]);
  useEffect(() => {
    storage.get("clientesconfig:tamano", true).then((r) => { if (r) setTamanoLogo(JSON.parse(r.value).tamano); }).catch(() => {});
  }, []);

  const guardarTamano = async (t) => {
    setTamanoLogo(t);
    await storage.set("clientesconfig:tamano", JSON.stringify({ tamano: t }), true);
  };

  const closeModal = () => {
    setShowAdd(false); setNombre(""); setFoto(null);
  };

  const handleFile = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 4.5 * 1024 * 1024) { alert("La foto es muy grande (máx ~4.5MB)."); return; }
    const reader = new FileReader();
    reader.onload = () => setFoto({ file, previewUrl: reader.result });
    reader.readAsDataURL(file);
  };

  const submit = async (e) => {
    e.preventDefault();
    if (!nombre.trim() || !foto) return;
    setSaving(true);
    try {
      const uploaded = await uploadToCloudinary(foto.file);
      const id = "clientes:" + Date.now();
      await storage.set(id, JSON.stringify({ nombre, foto: uploaded.url, fecha: new Date().toISOString() }), true);
      closeModal();
      await refresh();
      setCurrent(0);
    } catch {
      alert("No se pudo guardar el cliente. Intenta de nuevo.");
    } finally {
      setSaving(false);
    }
  };

  const n = items.length;
  const next = () => n && setCurrent((c) => (c + 1) % n);
  const prev = () => n && setCurrent((c) => (c - 1 + n) % n);

  return (
    <div style={{ background: C.bg, padding: "8vh 8vw", minHeight: "80vh" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 20 }}>
        <SectionHead eyebrow="Confían en nosotros" title="Nuestros clientes" />
        {isAdmin && (
          <button onClick={() => setShowAdd(true)} style={{
            background: C.gold, color: C.navy, border: "none", borderRadius: 10,
            padding: "12px 20px", fontWeight: 700, cursor: "pointer",
            display: "flex", alignItems: "center", gap: 8, flexShrink: 0,
          }}>
            <Plus size={17} /> Agregar
          </button>
        )}
      </div>

      {showAdd && (
        <div onClick={closeModal} style={{
          position: "fixed", inset: 0, background: "rgba(2,6,16,0.7)", zIndex: 100,
          display: "flex", alignItems: "center", justifyContent: "center", padding: 20,
        }}>
          <div onClick={(e) => e.stopPropagation()} style={{
            background: C.panel, border: `1px solid ${C.line}`, borderRadius: 18,
            padding: 30, maxWidth: 400, width: "100%", position: "relative",
          }}>
            <button onClick={closeModal} style={{ position: "absolute", top: 14, right: 14, background: "transparent", border: "none", color: C.textDim, cursor: "pointer" }}>
              <X size={18} />
            </button>
            <form onSubmit={submit}>
                <h3 style={{ fontFamily: "Arial, Helvetica, sans-serif", color: C.text, marginBottom: 18 }}>Nuevo cliente</h3>
                <label style={{ fontSize: 13, color: C.textDim, display: "block", marginBottom: 7, fontFamily: "Arial, Helvetica, sans-serif" }}>NOMBRE DE LA EMPRESA</label>
                <input
                  value={nombre} onChange={(e) => setNombre(e.target.value)}
                  style={{ width: "100%", background: C.bg, border: `1px solid ${C.line}`, borderRadius: 10, padding: "12px 14px", color: C.text, outline: "none", marginBottom: 18 }}
                  placeholder="Nombre de la empresa"
                />
                <label style={{
                  display: "flex", alignItems: "center", gap: 10, background: C.bg,
                  border: `1px dashed ${C.line}`, borderRadius: 10, padding: 14, cursor: "pointer", marginBottom: 18,
                }}>
                  <Upload size={18} color={C.blueLight} />
                  <span style={{ color: C.textDim, fontSize: 14 }}>{foto ? "Foto seleccionada ✓" : "Subir foto de la empresa"}</span>
                  <input type="file" accept="image/*" onChange={handleFile} style={{ display: "none" }} />
                </label>
                {foto && (
                  <img src={foto.previewUrl} alt="preview" style={{ width: 70, height: 70, borderRadius: "50%", objectFit: "cover", marginBottom: 18, border: `2px solid ${C.blueLight}` }} />
                )}
                <button type="submit" disabled={saving || !nombre.trim() || !foto} style={{
                  width: "100%", background: C.gold, color: C.navy, border: "none", borderRadius: 10,
                  padding: "13px 0", fontWeight: 700, cursor: "pointer",
                  opacity: (saving || !nombre.trim() || !foto) ? 0.6 : 1,
                }}>
                  {saving ? "Guardando..." : "Agregar cliente"}
                </button>

                <div style={{ marginTop: 22, paddingTop: 18, borderTop: `1px solid ${C.line}` }}>
                  <label style={{ fontSize: 13, color: C.textDim, display: "block", marginBottom: 9, fontFamily: "Arial, Helvetica, sans-serif" }}>TAMAÑO DE LOS LOGOS</label>
                  <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
                    {TAMANOS_LOGO.map(([l, t]) => (
                      <button key={t} type="button" onClick={() => guardarTamano(t)} style={{
                        background: tamanoLogo === t ? C.blue : "transparent", color: tamanoLogo === t ? "#fff" : C.textDim,
                        border: `1px solid ${C.line}`, borderRadius: 8, padding: "7px 12px", cursor: "pointer", fontSize: 12.5,
                      }}>{l}</button>
                    ))}
                  </div>
                </div>
              </form>
          </div>
        </div>
      )}

      {loading ? (
        <div style={{ color: C.textDim, marginTop: 30, display: "flex", alignItems: "center", gap: 8 }}>
          <Loader2 size={16} className="animate-spin" /> Cargando clientes…
        </div>
      ) : items.length === 0 ? (
        <div style={{ color: C.textDim, maxWidth: 520, display: "flex", alignItems: "flex-start", gap: 12, marginTop: 30 }}>
          <Users size={20} color={C.blueLight} style={{ flexShrink: 0, marginTop: 2 }} />
          <p style={{ margin: 0, lineHeight: 1.6 }}>
            Aún no hay clientes agregados. Usa "Agregar" para sumar el primero.
          </p>
        </div>
      ) : (
        <>
          <div style={{ position: "relative", marginTop: 50, height: tamanoLogo + 110, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <div style={{
              position: "absolute", width: `min(${tamanoLogo * 4.3}px,88%)`, height: tamanoLogo,
              border: `1px solid ${C.line}`, borderRadius: "50%",
              boxShadow: `0 0 40px ${C.blue}22 inset`, pointerEvents: "none",
            }} />
            <button onClick={prev} aria-label="Anterior" style={{
              position: "absolute", left: 0, zIndex: 20, background: C.bg,
              border: `1px solid ${C.line}`, borderRadius: "50%", width: 38, height: 38,
              color: C.text, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center",
            }}>
              <ChevronLeft size={19} />
            </button>
            <div style={{ position: "relative", width: "100%", height: "100%" }}>
              {items.map((it, i) => {
                let offset = i - current;
                if (offset > n / 2) offset -= n;
                if (offset < -n / 2) offset += n;
                if (Math.abs(offset) > 2) return null;
                const scale = offset === 0 ? 1 : Math.abs(offset) === 1 ? 0.72 : 0.5;
                const opacity = 1 - Math.abs(offset) * 0.32;
                return (
                  <div
                    key={it.key} onClick={() => setCurrent(i)}
                    style={{
                      position: "absolute", top: "50%", left: "50%", cursor: "pointer",
                      transition: "transform .45s cubic-bezier(.2,.8,.2,1), opacity .45s ease",
                      transform: `translate(-50%,-50%) translateX(${offset * tamanoLogo * 0.87}px) scale(${scale})`,
                      zIndex: 10 - Math.abs(offset), opacity,
                    }}
                  >
                    <div style={{
                      width: tamanoLogo, height: tamanoLogo, borderRadius: "50%", overflow: "hidden",
                      border: `3px solid ${offset === 0 ? C.gold : C.blueLight}`,
                      boxShadow: offset === 0 ? `0 0 30px ${C.blue}99` : "none",
                      background: C.panel,
                    }}>
                      <img src={it.foto} alt={it.nombre} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                    </div>
                  </div>
                );
              })}
            </div>
            <button onClick={next} aria-label="Siguiente" style={{
              position: "absolute", right: 0, zIndex: 20, background: C.bg,
              border: `1px solid ${C.line}`, borderRadius: "50%", width: 38, height: 38,
              color: C.text, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center",
            }}>
              <ChevronRight size={19} />
            </button>
          </div>
          <div style={{ textAlign: "center", marginTop: 24, color: C.text, fontFamily: "Arial, Helvetica, sans-serif", fontSize: 20, fontWeight: 700 }}>
            {items[current]?.nombre}
          </div>
        </>
      )}
    </div>
  );
}

// ================= REVISTA =================
function Revista({ isAdmin }) {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState(null);

  const [showForm, setShowForm] = useState(false);
  const [modo, setModo] = useState("texto"); // "texto" | "archivo"
  const [titulo, setTitulo] = useState("");
  const [enunciado, setEnunciado] = useState("");
  const [contenido, setContenido] = useState("");
  const [autor, setAutor] = useState("");
  const [foto, setFoto] = useState(null);
  const [archivo, setArchivo] = useState(null);
  const [published, setPublished] = useState(false);
  const [saving, setSaving] = useState(false);

  const [showSubscribe, setShowSubscribe] = useState(false);
  const [subNombre, setSubNombre] = useState("");
  const [subCorreo, setSubCorreo] = useState("");
  const [subMotivo, setSubMotivo] = useState("");
  const [subSaving, setSubSaving] = useState(false);
  const [subDone, setSubDone] = useState(false);

  const refresh = useCallback(async () => {
    setLoading(true);
    const data = await loadCollection("revista:");
    data.sort((a, b) => (b.fecha || "").localeCompare(a.fecha || ""));
    setItems(data);
    setLoading(false);
  }, []);

  useEffect(() => { refresh(); }, [refresh]);

  const resetForm = () => {
    setTitulo(""); setEnunciado(""); setContenido(""); setAutor("");
    setFoto(null); setArchivo(null); setModo("texto");
  };

  const handleFoto = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 4.5 * 1024 * 1024) { alert("La foto es muy grande (máx ~4.5MB)."); return; }
    const reader = new FileReader();
    reader.onload = () => setFoto({ file, previewUrl: reader.result });
    reader.readAsDataURL(file);
  };

  const handleArchivo = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 4.5 * 1024 * 1024) { alert("El archivo es muy grande (máx ~4.5MB)."); return; }
    setArchivo({ file, nombre: file.name, tipo: file.type || "application/octet-stream" });
  };

  const submitArticulo = async (e) => {
    e.preventDefault();
    if (!titulo.trim() || !enunciado.trim()) return;
    if (modo === "archivo" && !archivo) return;
    if (modo === "texto" && !contenido.trim()) return;
    setSaving(true);
    try {
      const id = "revista:" + Date.now();
      const fotoUploaded = foto ? await uploadToCloudinary(foto.file) : null;
      const archivoUploaded = modo === "archivo" && archivo ? await uploadToCloudinary(archivo.file) : null;
      await storage.set(id, JSON.stringify({
        titulo, enunciado, autor, tipo: modo,
        contenido: modo === "texto" ? contenido : "",
        archivo: archivoUploaded ? { url: archivoUploaded.url, nombre: archivo.nombre, tipo: archivo.tipo } : null,
        foto: fotoUploaded ? { url: fotoUploaded.url } : null,
        fecha: new Date().toISOString(),
      }), true);
      resetForm();
      setShowForm(false);
      await refresh();
      setPublished(true);
      setTimeout(() => setPublished(false), 6000);
    } catch {
      alert("No se pudo publicar el artículo. Intenta de nuevo.");
    } finally {
      setSaving(false);
    }
  };

  const removeArticulo = async (it) => {
    if (!confirm(`¿Eliminar el artículo "${it.titulo}"?`)) return;
    await storage.delete(it.key, true);
    if (selected?.key === it.key) setSelected(null);
    await refresh();
  };

  const download = (it) => {
    if (!it.archivo) return;
    window.open(it.archivo.url, "_blank");
  };

  const openArticle = (it) => {
    if (it.tipo === "archivo") download(it);
    else setSelected(it);
  };

  const submitSubscribe = async (e) => {
    e.preventDefault();
    if (!subNombre.trim() || !subCorreo.trim()) return;
    setSubSaving(true);
    try {
      const id = "escritores:" + Date.now();
      await storage.set(id, JSON.stringify({
        nombre: subNombre, correo: subCorreo, motivo: subMotivo, fecha: new Date().toISOString(),
      }), true);
      sendEmailNotification({
        subject: "Solicitud para escribir en la revista — SICODE",
        fromName: "Revista SICODE",
        data: { nombre: subNombre, correo: subCorreo, motivo: subMotivo },
      });
      setSubDone(true);
      setSubNombre(""); setSubCorreo(""); setSubMotivo("");
    } catch {
      alert("No se pudo enviar tu solicitud. Intenta de nuevo.");
    } finally {
      setSubSaving(false);
    }
  };

  const inputStyle = {
    width: "100%", background: C.bg, border: `1px solid ${C.line}`, borderRadius: 10,
    padding: "12px 14px", color: C.text, fontSize: 14.5, outline: "none", fontFamily: "Arial, Helvetica, sans-serif",
  };

  // separa el contenido de un artículo de texto en "intro" (primer párrafo) y "resto"
  const splitContenido = (txt) => {
    const parts = (txt || "").split(/\n\s*\n/);
    return { intro: parts[0] || "", resto: parts.slice(1).join("\n\n") };
  };

  return (
    <div style={{ background: C.bg, padding: "8vh 8vw", minHeight: "80vh" }}>
      {published && (
        <div style={{
          display: "flex", alignItems: "center", gap: 8, color: C.blueLight,
          background: C.blueLight + "18", border: `1px solid ${C.blueLight}55`,
          borderRadius: 10, padding: "12px 16px", fontSize: 14, marginBottom: 20,
        }}>
          <CheckCircle2 size={18} />
          El artículo se agregó correctamente.
        </div>
      )}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 20 }}>
        <SectionHead eyebrow="Revista SICODE" title="Artículos y primicias" />
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
          <button onClick={() => setShowSubscribe(true)} style={{
            background: "rgba(16,48,107,0.12)", color: C.blueLight, border: "none", borderRadius: 10,
            padding: "12px 18px", fontWeight: 700, cursor: "pointer", display: "flex", alignItems: "center", gap: 8,
          }}>
            <Newspaper size={16} /> Quiero escribir
          </button>
          {isAdmin && (
            <button onClick={() => setShowForm(true)} style={{
              background: C.gold, color: C.navy, border: "none", borderRadius: 10,
              padding: "12px 18px", fontWeight: 700, cursor: "pointer", display: "flex", alignItems: "center", gap: 8,
            }}>
              <Plus size={16} /> Nuevo artículo
            </button>
          )}
        </div>
      </div>

      <p style={{ color: C.textDim, maxWidth: 640, marginTop: -20, marginBottom: 44 }}>
        Solo se muestra el enunciado o primicia de cada artículo. Haz clic para leerlo completo o
        descargar el documento, según corresponda.
      </p>

      {loading ? (
        <div style={{ color: C.textDim, display: "flex", alignItems: "center", gap: 8 }}>
          <Loader2 size={16} className="animate-spin" /> Cargando artículos…
        </div>
      ) : items.length === 0 ? (
        <div style={{ color: C.textDim }}>Aún no hay artículos publicados.</div>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(280px,1fr))", gap: 18 }}>
          {items.map((it) => (
            <div key={it.key} style={{
              background: C.panel, border: `1px solid ${C.line}`, borderRadius: 14, overflow: "hidden",
              display: "flex", flexDirection: "column", cursor: "pointer",
            }} onClick={() => openArticle(it)}>
              {it.foto && (
                <div style={{ height: 150, overflow: "hidden" }}>
                  <img src={it.foto.url} alt={it.titulo} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                </div>
              )}
              <div style={{ padding: 20, display: "flex", flexDirection: "column", gap: 10, flex: 1 }}>
                <div style={{ color: C.text, fontFamily: "Arial, Helvetica, sans-serif", fontWeight: 700, fontSize: 17 }}>{it.titulo}</div>
                <p style={{ color: C.textDim, margin: 0, lineHeight: 1.5, fontSize: 14, flex: 1 }}>{it.enunciado}</p>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 8 }}>
                  <span style={{ color: C.blueLight, fontSize: 13, display: "flex", alignItems: "center", gap: 6, fontFamily: "Arial, Helvetica, sans-serif" }}>
                    {it.tipo === "archivo" ? (<><Download size={14} /> Descargar</>) : (<><ChevronRight size={14} /> Leer más</>)}
                  </span>
                  {isAdmin && (
                    <button onClick={(e) => { e.stopPropagation(); removeArticulo(it); }} style={{ background: "rgba(255,90,90,0.12)", color: "#FF8080", border: "none", borderRadius: 8, padding: "6px 8px", cursor: "pointer" }}>
                      <Trash2 size={14} />
                    </button>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Detalle de artículo de texto: foto al lado de la intro, y abajo el resto del texto en página completa */}
      {selected && (
        <div onClick={() => setSelected(null)} style={{
          position: "fixed", inset: 0, background: "rgba(2,6,16,0.85)", zIndex: 100,
          overflowY: "auto", padding: "6vh 5vw",
        }}>
          <div onClick={(e) => e.stopPropagation()} style={{
            background: C.bg, border: `1px solid ${C.line}`, borderRadius: 18,
            padding: "5vh 6vw", maxWidth: 880, margin: "0 auto", position: "relative",
          }}>
            <button onClick={() => setSelected(null)} style={{ position: "absolute", top: 18, right: 18, background: "transparent", border: "none", color: C.textDim, cursor: "pointer" }}>
              <X size={22} />
            </button>
            <div style={{ fontFamily: "Arial, Helvetica, sans-serif", fontSize: 12, letterSpacing: "0.14em", color: C.gold, textTransform: "uppercase", marginBottom: 10 }}>
              {selected.autor ? `Por ${selected.autor}` : "SICODE"}
            </div>
            <h2 style={{ fontFamily: "Arial, Helvetica, sans-serif", color: C.text, fontSize: "clamp(1.6rem,3.4vw,2.3rem)", marginBottom: 26 }}>
              {selected.titulo}
            </h2>
            {(() => {
              const { intro, resto } = splitContenido(selected.contenido);
              return (
                <>
                  <div style={{ display: "flex", gap: 28, flexWrap: "wrap", alignItems: "flex-start", marginBottom: 30 }}>
                    {selected.foto && (
                      <img
                        src={selected.foto.url}
                        alt={selected.titulo}
                        style={{ width: 260, maxWidth: "100%", borderRadius: 14, objectFit: "cover", flexShrink: 0 }}
                      />
                    )}
                    <p style={{ color: C.text, lineHeight: 1.8, fontSize: 16, margin: 0, flex: "1 1 300px" }}>{intro}</p>
                  </div>
                  {resto && (
                    <div style={{ color: C.textDim, lineHeight: 1.9, fontSize: 15.5, whiteSpace: "pre-wrap" }}>{resto}</div>
                  )}
                </>
              );
            })()}
          </div>
        </div>
      )}

      {/* Formulario para publicar artículo (solo admin) */}
      {showForm && isAdmin && (
        <div onClick={() => setShowForm(false)} style={{
          position: "fixed", inset: 0, background: "rgba(2,6,16,0.7)", zIndex: 100,
          display: "flex", alignItems: "center", justifyContent: "center", padding: 20, overflowY: "auto",
        }}>
          <form onSubmit={submitArticulo} onClick={(e) => e.stopPropagation()} style={{
            background: C.panel, border: `1px solid ${C.line}`, borderRadius: 18, padding: 30,
            maxWidth: 520, width: "100%", position: "relative", display: "flex", flexDirection: "column", gap: 14, margin: "4vh 0",
          }}>
            <button type="button" onClick={() => setShowForm(false)} style={{ position: "absolute", top: 14, right: 14, background: "transparent", border: "none", color: C.textDim, cursor: "pointer" }}><X size={18} /></button>
            <h3 style={{ fontFamily: "Arial, Helvetica, sans-serif", color: C.text, margin: 0 }}>Nuevo artículo</h3>

            <input style={inputStyle} placeholder="Título" value={titulo} onChange={(e) => setTitulo(e.target.value)} />
            <textarea style={{ ...inputStyle, minHeight: 70, resize: "vertical" }} placeholder="Enunciado o primicia (lo único que verá el público antes de abrir)" value={enunciado} onChange={(e) => setEnunciado(e.target.value)} />
            <input style={inputStyle} placeholder="Autor (opcional)" value={autor} onChange={(e) => setAutor(e.target.value)} />

            <label style={{ display: "flex", alignItems: "center", gap: 10, background: C.bg, border: `1px dashed ${C.line}`, borderRadius: 10, padding: 12, cursor: "pointer" }}>
              <Upload size={17} color={C.blueLight} />
              <span style={{ color: C.textDim, fontSize: 13.5 }}>{foto ? "Foto de inicio seleccionada ✓" : "Foto de inicio (opcional, va al lado del texto)"}</span>
              <input type="file" accept="image/*" onChange={handleFoto} style={{ display: "none" }} />
            </label>

            <div style={{ display: "flex", gap: 10 }}>
              <button type="button" onClick={() => setModo("texto")} style={{
                flex: 1, padding: "10px 0", borderRadius: 8, cursor: "pointer", fontSize: 13.5,
                border: `1px solid ${modo === "texto" ? C.blueLight : C.line}`,
                background: modo === "texto" ? "rgba(16,48,107,0.12)" : "transparent",
                color: modo === "texto" ? C.blueLight : C.textDim,
              }}>Escribir aquí</button>
              <button type="button" onClick={() => setModo("archivo")} style={{
                flex: 1, padding: "10px 0", borderRadius: 8, cursor: "pointer", fontSize: 13.5,
                border: `1px solid ${modo === "archivo" ? C.blueLight : C.line}`,
                background: modo === "archivo" ? "rgba(16,48,107,0.12)" : "transparent",
                color: modo === "archivo" ? C.blueLight : C.textDim,
              }}>Subir documento</button>
            </div>

            {modo === "texto" ? (
              <textarea style={{ ...inputStyle, minHeight: 160, resize: "vertical" }} placeholder="Contenido completo del artículo. Deja una línea en blanco después del primer párrafo: ese párrafo se mostrará junto a la foto, y el resto abajo a página completa." value={contenido} onChange={(e) => setContenido(e.target.value)} />
            ) : (
              <label style={{ display: "flex", alignItems: "center", gap: 10, background: C.bg, border: `1px dashed ${C.line}`, borderRadius: 10, padding: 12, cursor: "pointer" }}>
                <Upload size={17} color={C.blueLight} />
                <span style={{ color: C.textDim, fontSize: 13.5 }}>{archivo ? `${archivo.nombre} ✓` : "Subir documento (PDF, Word, etc.)"}</span>
                <input type="file" onChange={handleArchivo} style={{ display: "none" }} />
              </label>
            )}

            <button type="submit" disabled={saving} style={{
              background: C.gold, color: C.navy, border: "none", borderRadius: 10, padding: "13px 0",
              fontWeight: 700, cursor: "pointer", opacity: saving ? 0.7 : 1,
              display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
            }}>
              {saving ? <Loader2 size={16} className="animate-spin" /> : <Send size={16} />}
              Publicar artículo
            </button>
          </form>
        </div>
      )}

      {/* Suscripción para escribir en la revista */}
      {showSubscribe && (
        <div onClick={() => { setShowSubscribe(false); setSubDone(false); }} style={{
          position: "fixed", inset: 0, background: "rgba(2,6,16,0.7)", zIndex: 100,
          display: "flex", alignItems: "center", justifyContent: "center", padding: 20,
        }}>
          <div onClick={(e) => e.stopPropagation()} style={{ background: C.panel, border: `1px solid ${C.line}`, borderRadius: 18, padding: 30, maxWidth: 420, width: "100%", position: "relative" }}>
            <button onClick={() => { setShowSubscribe(false); setSubDone(false); }} style={{ position: "absolute", top: 14, right: 14, background: "transparent", border: "none", color: C.textDim, cursor: "pointer" }}><X size={18} /></button>
            {subDone ? (
              <div style={{ textAlign: "center", padding: "20px 0" }}>
                <CheckCircle2 size={32} color={C.gold} style={{ marginBottom: 12 }} />
                <p style={{ color: C.text }}>¡Gracias! Recibimos tu solicitud para escribir en la revista. Te contactaremos pronto.</p>
              </div>
            ) : (
              <form onSubmit={submitSubscribe} style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                <h3 style={{ fontFamily: "Arial, Helvetica, sans-serif", color: C.text, margin: 0 }}>Quiero escribir en la revista</h3>
                <p style={{ color: C.textDim, fontSize: 13.5, margin: 0 }}>Déjanos tus datos y con gusto te contactamos para sumarte como colaborador.</p>
                <input style={inputStyle} placeholder="Tu nombre" value={subNombre} onChange={(e) => setSubNombre(e.target.value)} />
                <input style={inputStyle} placeholder="Tu correo" value={subCorreo} onChange={(e) => setSubCorreo(e.target.value)} />
                <textarea style={{ ...inputStyle, minHeight: 70, resize: "vertical" }} placeholder="¿Sobre qué te gustaría escribir? (opcional)" value={subMotivo} onChange={(e) => setSubMotivo(e.target.value)} />
                <button type="submit" disabled={subSaving} style={{
                  background: C.gold, color: C.navy, border: "none", borderRadius: 10, padding: "12px 0",
                  fontWeight: 700, cursor: "pointer", opacity: subSaving ? 0.7 : 1,
                }}>
                  {subSaving ? "Enviando..." : "Enviar solicitud"}
                </button>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ================= ADMIN =================
function Admin({ isAdmin, onAbrirLogin }) {
  const [inscripciones, setInscripciones] = useState([]);
  const [escritores, setEscritores] = useState([]);
  const [respuestasForm, setRespuestasForm] = useState([]);
  const [loading, setLoading] = useState(false);

  const load = async () => {
    setLoading(true);
    const data = await loadCollection("inscripciones:");
    data.sort((a, b) => (b.fecha || "").localeCompare(a.fecha || ""));
    setInscripciones(data);
    const w = await loadCollection("escritores:");
    w.sort((a, b) => (b.fecha || "").localeCompare(a.fecha || ""));
    setEscritores(w);
    const r = await loadCollection("formresp:");
    r.sort((a, b) => (b.fecha || "").localeCompare(a.fecha || ""));
    setRespuestasForm(r);
    setLoading(false);
  };

  useEffect(() => { if (isAdmin) load(); }, [isAdmin]);

  if (!isAdmin) {
    return (
      <div style={{ minHeight: "70vh", display: "flex", alignItems: "center", justifyContent: "center", background: C.bg, padding: "8vh 8vw" }}>
        <div style={{ maxWidth: 360, width: "100%", textAlign: "center" }}>
          <Lock size={30} color={C.blueLight} style={{ marginBottom: 16 }} />
          <h2 style={{ fontFamily: "Arial, Helvetica, sans-serif", color: C.text, marginBottom: 10 }}>Panel administrador</h2>
          <p style={{ color: C.textDim, fontSize: 14, marginBottom: 18 }}>Inicia sesión desde el candado en la parte de arriba del sitio para entrar aquí.</p>
          <button onClick={onAbrirLogin} style={{ background: C.gold, color: C.navy, border: "none", borderRadius: 10, padding: "12px 22px", fontWeight: 700, cursor: "pointer" }}>
            Iniciar sesión de administrador
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ background: C.bg, padding: "8vh 8vw", minHeight: "80vh" }}>
      <SectionHead eyebrow="Panel administrador" title="Inscripciones recibidas" />
      {loading ? (
        <div style={{ color: C.textDim, display: "flex", alignItems: "center", gap: 8 }}><Loader2 size={16} className="animate-spin" /> Cargando…</div>
      ) : inscripciones.length === 0 ? (
        <div style={{ color: C.textDim }}>Aún no hay inscripciones.</div>
      ) : (
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", minWidth: 780 }}>
            <thead>
              <tr style={{ textAlign: "left", color: C.textDim, fontFamily: "Arial, Helvetica, sans-serif", fontSize: 12, borderBottom: `1px solid ${C.line}` }}>
                {["Nombre", "Apellido", "Contacto", "Cédula", "Correo", "Horario", "Dirección"].map((h) => (
                  <th key={h} style={{ padding: "10px 12px" }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {inscripciones.map((r) => (
                <tr key={r.key} style={{ borderBottom: `1px solid ${C.line}`, color: C.text, fontSize: 13.5 }}>
                  <td style={{ padding: "10px 12px" }}>{r.nombre}</td>
                  <td style={{ padding: "10px 12px" }}>{r.apellido}</td>
                  <td style={{ padding: "10px 12px" }}>{r.contacto}</td>
                  <td style={{ padding: "10px 12px" }}>{r.cedula}</td>
                  <td style={{ padding: "10px 12px" }}>{r.correo}</td>
                  <td style={{ padding: "10px 12px" }}>{r.horario}</td>
                  <td style={{ padding: "10px 12px" }}>{r.direccion}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <div style={{ marginTop: 60 }}>
        <SectionHead eyebrow="Formularios" title="Gestionar formularios (crear / eliminar)" />
        <GestionFormularios />
      </div>

      <div style={{ marginTop: 60 }}>
        <SectionHead eyebrow="Formularios" title="Respuestas recibidas" />
        {loading ? (
          <div style={{ color: C.textDim }}>Cargando…</div>
        ) : respuestasForm.length === 0 ? (
          <div style={{ color: C.textDim }}>Aún no hay respuestas en los formularios nuevos.</div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {respuestasForm.map((r) => (
              <div key={r.key} style={{ background: C.panel, border: `1px solid ${C.line}`, borderRadius: 12, padding: 14 }}>
                <div style={{ color: C.gold, fontFamily: "Arial, Helvetica, sans-serif", fontWeight: 700, fontSize: 13.5, marginBottom: 6 }}>{r.formularioTitulo || "Formulario"}</div>
                <div style={{ display: "flex", flexWrap: "wrap", gap: "4px 18px" }}>
                  {Object.entries(r).filter(([k]) => !["key", "formularioTitulo", "fecha"].includes(k)).map(([k, v]) => (
                    <div key={k} style={{ fontSize: 12.5, color: C.text }}><span style={{ color: C.textDim }}>{k}:</span> {String(v)}</div>
                  ))}
                </div>
                <div style={{ color: C.textDim, fontSize: 11, marginTop: 6 }}>{r.fecha ? new Date(r.fecha).toLocaleString() : ""}</div>
              </div>
            ))}
          </div>
        )}
      </div>

      <div style={{ marginTop: 60 }}>
        <SectionHead eyebrow="Revista" title="Solicitudes para escribir" />
        {loading ? (
          <div style={{ color: C.textDim }}>Cargando…</div>
        ) : escritores.length === 0 ? (
          <div style={{ color: C.textDim }}>Aún no hay solicitudes de personas que quieran escribir.</div>
        ) : (
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse", minWidth: 640 }}>
              <thead>
                <tr style={{ textAlign: "left", color: C.textDim, fontFamily: "Arial, Helvetica, sans-serif", fontSize: 12, borderBottom: `1px solid ${C.line}` }}>
                  {["Nombre", "Correo", "Motivo/Tema"].map((h) => (
                    <th key={h} style={{ padding: "10px 12px" }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {escritores.map((r) => (
                  <tr key={r.key} style={{ borderBottom: `1px solid ${C.line}`, color: C.text, fontSize: 13.5 }}>
                    <td style={{ padding: "10px 12px" }}>{r.nombre}</td>
                    <td style={{ padding: "10px 12px" }}>{r.correo}</td>
                    <td style={{ padding: "10px 12px" }}>{r.motivo}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

// ================= FEEDBACK MODAL =================
function FeedbackModal({ open, onClose, onYes }) {
  if (!open) return null;
  return (
    <div style={{
      position: "fixed", inset: 0, background: "rgba(2,6,16,0.65)", zIndex: 100,
      display: "flex", alignItems: "center", justifyContent: "center", padding: 20,
    }}>
      <div style={{ background: C.panel, border: `1px solid ${C.line}`, borderRadius: 18, padding: 32, maxWidth: 380, position: "relative" }}>
        <button onClick={onClose} style={{ position: "absolute", top: 14, right: 14, background: "transparent", border: "none", color: C.textDim, cursor: "pointer" }}>
          <X size={18} />
        </button>
        <MessageCircle size={28} color={C.blueLight} style={{ marginBottom: 14 }} />
        <h3 style={{ fontFamily: "Arial, Helvetica, sans-serif", color: C.text, fontSize: 20, margin: "0 0 10px" }}>Tu opinión cuenta</h3>
        <p style={{ color: C.textDim, fontSize: 14.5, lineHeight: 1.5, margin: "0 0 22px" }}>¿Te gustaría dejar un comentario sobre el sitio?</p>
        <div style={{ display: "flex", gap: 10 }}>
          <button onClick={onYes} style={{ flex: 1, background: C.gold, color: C.navy, border: "none", borderRadius: 10, padding: "11px 0", fontWeight: 700, cursor: "pointer" }}>Sí, comentar</button>
          <button onClick={onClose} style={{ flex: 1, background: "transparent", border: `1px solid ${C.line}`, color: C.text, borderRadius: 10, padding: "11px 0", cursor: "pointer" }}>Ahora no</button>
        </div>
      </div>
    </div>
  );
}

